import {
  Check,
  Image as ImageIcon,
  Plus,
  Trash2,
  X,
  Upload,
  Loader2,
} from "lucide-react";
import { useEffect, useState, useRef } from "react";
import { toast } from "react-hot-toast";
import { io } from "socket.io-client";
import { adminService } from "../services/adminService";
import API from "../services/api";

const Banners = () => {
  const [banners, setBanners] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("");
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({
    title: "",
    subtitle: "",
    brandLabel: "CLICK DELIVER",
    imageUrl: "",
    days: 1,
    targetType: "none",
    city: "",
    dailyRate: 500,
  });
  const [uploadingImage, setUploadingImage] = useState(false);
  const fileInputRef = useRef(null);

  const load = async () => {
    try {
      setLoading(true);
      const data = await adminService.getBanners(filter || undefined);
      setBanners(data);
    } catch (error) {
      toast.error(error.message || "Failed to load banners");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, [filter]);

  useEffect(() => {
    const socketBaseUrl = API.defaults.baseURL.replace("/api", "");
    const socket = io(socketBaseUrl, { transports: ["websocket", "polling"] });

    socket.on("admin:bannerRequest", (banner) => {
      // Reload banners when a new request comes in
      load();
    });

    return () => socket.disconnect();
  }, []);

  const handleImageSelect = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setUploadingImage(true);
    try {
      const data = await adminService.uploadImage(file);
      setForm((prev) => ({ ...prev, imageUrl: data.imageUrl }));
    } catch (error) {
      toast.error("Failed to upload image");
    } finally {
      setUploadingImage(false);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      await adminService.createBanner(form);
      toast.success("Banner published successfully!");
      setForm({
        title: "",
        subtitle: "",
        brandLabel: "CLICK DELIVER",
        imageUrl: "",
        days: 1,
        targetType: "none",
        city: "",
        dailyRate: 500,
      });
      setShowModal(false);
      load();
    } catch (error) {
      toast.error(error.response?.data?.message || "Publish failed");
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setForm({
      title: "",
      subtitle: "",
      brandLabel: "CLICK DELIVER",
      imageUrl: "",
      days: 1,
      targetType: "none",
      city: "",
      dailyRate: 500,
    });
  };

  const handleApprove = async (id, markPaid) => {
    try {
      await adminService.approveBanner(id, markPaid);
      toast.success("Banner approved");
      load();
    } catch (error) {
      toast.error(error.response?.data?.message || "Approve failed");
    }
  };

  const handleReject = async (id) => {
    const reason = prompt("Reason for rejection:");
    if (reason === null) return;
    try {
      await adminService.rejectBanner(id, reason);
      toast.success("Banner rejected");
      load();
    } catch (error) {
      toast.error(error.response?.data?.message || "Reject failed");
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this banner?")) return;
    try {
      await adminService.deleteBanner(id);
      toast.success("Banner deleted");
      load();
    } catch (error) {
      toast.error(error.response?.data?.message || "Delete failed");
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case "approved":
        return "status-delivered";
      case "rejected":
        return "status-cancelled";
      case "pending_payment":
        return "status-pending";
      case "pending_review":
        return "status-transit";
      default:
        return "";
    }
  };

  return (
    <div className="content-area animate-fade-in">
      <div className="section-header">
        <div>
          <h1 style={{ display: "flex", alignItems: "center", gap: "8px" }}>
            <ImageIcon size={28} className="text-primary" />
            Banners Management
          </h1>
          <p className="section-subtitle">
            Manage home carousel ads. Shopkeepers pay Rs 500/day for promotion
            after admin approval.
          </p>
        </div>
        <button
          className="primary-btn icon-text-btn"
          onClick={() => setShowModal(true)}
        >
          <Plus size={18} /> New Banner
        </button>
      </div>

      {showModal && (
        <div className="modal-overlay">
          <div className="modal-content glass-panel animate-fade-in">
            <div className="modal-header">
              <h3>Create New Banner</h3>
              <button className="icon-btn close-btn" onClick={handleCloseModal}>
                <X size={20} />
              </button>
            </div>
            <form onSubmit={handleCreate} className="modal-form">
              <div className="form-grid">
                <div className="form-group">
                  <label>Title *</label>
                  <input
                    required
                    value={form.title}
                    onChange={(e) =>
                      setForm({ ...form, title: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Subtitle</label>
                  <input
                    value={form.subtitle}
                    onChange={(e) =>
                      setForm({ ...form, subtitle: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Duration (Days)</label>
                  <input
                    type="number"
                    min="1"
                    value={form.days}
                    onChange={(e) => setForm({ ...form, days: e.target.value })}
                  />
                </div>
                <div className="form-group">
                  <label>Daily Rate (PKR)</label>
                  <input
                    type="number"
                    min="0"
                    value={form.dailyRate}
                    onChange={(e) =>
                      setForm({ ...form, dailyRate: e.target.value })
                    }
                  />
                </div>
                <div className="form-group">
                  <label>Target City</label>
                  <input
                    placeholder="Leave empty for all"
                    value={form.city}
                    onChange={(e) => setForm({ ...form, city: e.target.value })}
                  />
                </div>
                <div className="form-group" style={{ gridColumn: "1 / -1" }}>
                  <label>Image *</label>
                  <div
                    className="image-upload-controls"
                    style={{ display: "flex", gap: "0.5rem" }}
                  >
                    <input
                      type="text"
                      placeholder="Paste URL or upload file →"
                      value={form.imageUrl}
                      onChange={(e) =>
                        setForm({ ...form, imageUrl: e.target.value })
                      }
                      style={{ flex: 1 }}
                      required
                    />
                    <input
                      type="file"
                      ref={fileInputRef}
                      style={{ display: "none" }}
                      accept="image/*"
                      onChange={handleImageSelect}
                    />
                    <button
                      type="button"
                      className="icon-btn"
                      onClick={() => fileInputRef.current.click()}
                      disabled={uploadingImage}
                      title="Upload from system"
                      style={{
                        height: "42px",
                        width: "42px",
                        backgroundColor: "var(--accent-primary)",
                        color: "white",
                        borderRadius: "8px",
                      }}
                    >
                      {uploadingImage ? (
                        <Loader2 size={18} className="animate-spin" />
                      ) : (
                        <Upload size={18} />
                      )}
                    </button>
                  </div>
                  {form.imageUrl && (
                    <div
                      className="image-preview-mini"
                      style={{ marginTop: "0.5rem" }}
                    >
                      <img
                        src={form.imageUrl}
                        alt="Preview"
                        style={{
                          height: "60px",
                          borderRadius: "4px",
                          border: "1px solid rgba(255,255,255,0.1)",
                        }}
                      />
                    </div>
                  )}
                </div>
              </div>
              <button
                type="submit"
                className="submit-btn primary-btn"
                style={{ marginTop: "1rem" }}
              >
                Publish Banner Now
              </button>
            </form>
          </div>
        </div>
      )}

      <div
        className="glass-panel"
        style={{ padding: "0.5rem", marginBottom: "1.5rem" }}
      >
        <div
          style={{
            display: "flex",
            gap: "0.5rem",
            flexWrap: "wrap",
            overflowX: "auto",
          }}
        >
          {[
            { id: "", label: "All Banners" },
            { id: "pending_review", label: "Pending Review" },
            { id: "pending_payment", label: "Pending Payment" },
            { id: "approved", label: "Active/Approved" },
            { id: "rejected", label: "Rejected" },
          ].map((tab) => (
            <button
              key={tab.id}
              onClick={() => setFilter(tab.id)}
              style={{
                padding: "0.625rem 1.25rem",
                borderRadius: "var(--radius-md)",
                border: "none",
                background:
                  filter === tab.id ? "var(--accent-primary)" : "transparent",
                color: filter === tab.id ? "white" : "var(--text-muted)",
                fontWeight: 500,
                fontSize: "0.875rem",
                cursor: "pointer",
                transition: "all 0.2s ease",
                whiteSpace: "nowrap",
              }}
              onMouseEnter={(e) => {
                if (filter !== tab.id) {
                  e.target.style.background = "rgba(255, 255, 255, 0.05)";
                }
              }}
              onMouseLeave={(e) => {
                if (filter !== tab.id) {
                  e.target.style.background = "transparent";
                }
              }}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {loading ? (
        <div className="table-loader">Loading banners...</div>
      ) : (
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))",
            gap: "1.5rem",
          }}
        >
          {banners.map((b) => (
            <div
              key={b._id}
              className="glass-panel"
              style={{
                display: "flex",
                flexDirection: "column",
                overflow: "hidden",
                padding: 0,
              }}
            >
              <div
                style={{
                  height: "140px",
                  background: "var(--bg-secondary)",
                  position: "relative",
                }}
              >
                <img
                  src={b.imageUrl}
                  alt={b.title}
                  style={{ width: "100%", height: "100%", objectFit: "cover" }}
                />
                <div
                  style={{
                    position: "absolute",
                    top: 10,
                    right: 10,
                    display: "flex",
                    gap: "5px",
                  }}
                >
                  <span
                    className={`status-pill ${getStatusColor(b.status)}`}
                    style={{
                      textTransform: "capitalize",
                      padding: "4px 8px",
                      fontSize: "11px",
                      backdropFilter: "blur(4px)",
                      background: "rgba(0,0,0,0.6)",
                    }}
                  >
                    {b.status.replace("_", " ")}
                  </span>
                  {b.source === "shopkeeper" && (
                    <span
                      className="status-pill status-pending"
                      style={{
                        textTransform: "capitalize",
                        padding: "4px 8px",
                        fontSize: "11px",
                        backdropFilter: "blur(4px)",
                        background: "rgba(0,0,0,0.6)",
                      }}
                    >
                      {b.paymentStatus}
                    </span>
                  )}
                </div>
              </div>
              <div
                style={{
                  padding: "16px",
                  flex: 1,
                  display: "flex",
                  flexDirection: "column",
                }}
              >
                <h3 style={{ margin: "0 0 4px 0", fontSize: "1.1rem" }}>
                  {b.title}
                </h3>
                <p
                  style={{
                    margin: 0,
                    color: "var(--text-muted)",
                    fontSize: "0.9rem",
                    flex: 1,
                  }}
                >
                  {b.subtitle || "No subtitle"}
                </p>

                <div
                  style={{
                    marginTop: "12px",
                    fontSize: "0.85rem",
                    color: "var(--text-secondary)",
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      marginBottom: "4px",
                    }}
                  >
                    <span>Source:</span>{" "}
                    <strong
                      style={{
                        color: "var(--text-main)",
                        textTransform: "capitalize",
                      }}
                    >
                      {b.source}
                    </strong>
                  </div>
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      marginBottom: "4px",
                    }}
                  >
                    <span>Duration:</span>{" "}
                    <strong style={{ color: "var(--text-main)" }}>
                      {b.days} Days
                    </strong>
                  </div>
                  <div
                    style={{
                      display: "flex",
                      justifyContent: "space-between",
                      marginBottom: "4px",
                    }}
                  >
                    <span>City:</span>{" "}
                    <strong style={{ color: "var(--text-main)" }}>
                      {b.city || "All"}
                    </strong>
                  </div>
                </div>

                <div
                  style={{
                    marginTop: "auto",
                    display: "flex",
                    gap: "8px",
                    paddingTop: "12px",
                    borderTop: "1px solid var(--border-color)",
                  }}
                >
                  {(b.status === "pending_review" ||
                    b.status === "pending_payment") && (
                    <button
                      className="primary-btn"
                      style={{
                        flex: 1,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        gap: "6px",
                        padding: "8px",
                      }}
                      onClick={() =>
                        handleApprove(b._id, b.paymentStatus !== "paid")
                      }
                    >
                      <Check size={16} /> Approve
                    </button>
                  )}
                  {b.status === "pending_review" && (
                    <button
                      className="view-btn"
                      style={{
                        flex: 1,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        gap: "6px",
                        padding: "8px",
                      }}
                      onClick={() => handleReject(b._id)}
                    >
                      <X size={16} /> Reject
                    </button>
                  )}
                  <button
                    className="icon-btn"
                    style={{
                      color: "#ef4444",
                      border: "1px solid var(--border-color)",
                      borderRadius: "var(--radius-md)",
                      padding: "8px",
                    }}
                    onClick={() => handleDelete(b._id)}
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            </div>
          ))}
          {banners.length === 0 && (
            <div
              style={{
                gridColumn: "1 / -1",
                textAlign: "center",
                padding: "3rem",
                color: "var(--text-muted)",
              }}
            >
              <ImageIcon
                size={48}
                style={{ opacity: 0.3, marginBottom: "1rem" }}
              />
              <p>No banners found matching your criteria.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default Banners;
